<article class="package-card h-100"><a class="package-media" href="<?php echo e(route('packages.show',$package)); ?>"><img src="<?php echo e($package->image_url); ?>" alt="<?php echo e($package->title); ?>" loading="lazy"><span><?php echo e($package->duration); ?></span></a><div class="package-body"><span class="mini-label"><?php echo e($package->trending ? 'Trending package' : 'Complete party plan'); ?></span><h3><a href="<?php echo e(route('packages.show',$package)); ?>"><?php echo e($package->title); ?></a></h3><p><?php echo e(\Illuminate\Support\Str::limit($package->description,82)); ?></p><ul><?php $__currentLoopData = array_slice($package->services ?? [],0,3); $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $serviceName): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><li><i class="fa-solid fa-check"></i> <?php echo e($serviceName); ?></li><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></ul><div class="package-footer"><div class="price-row"><small>Package price</small><span>&#8377;<?php echo e(number_format($package->effective_price)); ?></span><?php if($package->discount_price): ?><del>&#8377;<?php echo e(number_format((float)$package->price)); ?></del><?php endif; ?></div><div class="service-card-actions"><form method="post" action="<?php echo e(route('cart.add')); ?>"><?php echo csrf_field(); ?><input type="hidden" name="package_id" value="<?php echo e($package->id); ?>"><input type="hidden" name="city_id" value="<?php echo e($selectedCity?->id); ?>"><button class="icon-link" title="Add package to cart"><i class="fa-solid fa-cart-plus"></i></button></form><a class="btn btn-dark btn-sm" href="<?php echo e(route('booking.create',['package'=>$package->slug])); ?>">Book now</a></div></div></div></article>
